const leads = $input.first().json.data || [];

const toAudit = leads
  .filter(l => l.website && (l.website.startsWith('http://') || l.website.startsWith('https://')))
  .filter(l => l.websiteScore === '0' || l.websiteScore === '' || !l.websiteScore)
  .slice(0, 5)
  .map(l => ({
    leadId: l.id,
    businessName: l.businessName,
    website: l.website,
    email: l.email,
    phone: l.phone,
    city: l.city || '',
    state: l.state || ''
  }));

return { leads: toAudit, count: toAudit.length, timestamp: new Date().toISOString() };

const allInputs = $input.all();

const htmlResp = allInputs.find(i => i.json.body || i.json.data);
const psResp = allInputs.find(i => i.json.lighthouseResult);

const html = String(htmlResp?.json?.body || htmlResp?.json?.data || '');
const finalUrl = htmlResp?.json?.url || htmlResp?.json?.requestUrl || '';
const statusCode = htmlResp?.json?.statusCode || 0;

const analysis = {
  url: finalUrl,
  statusCode: statusCode,
  isAccessible: statusCode >= 200 && statusCode < 400,
  hasHttps: finalUrl.startsWith('https://'),
  hasForm: /<form\b[^>]*>/i.test(html),
  hasPhoneLink: /tel:[\d\-+()\s]{7,}/i.test(html),
  hasEmailLink: /mailto:[\w.+-]+@[\w.-]+\.[a-z]{2,}/i.test(html),
  hasCTA: /(contact us|get.*quote|free consultation|schedule|book now|get started|request|inquire)/i.test(html),
  hasViewport: /<meta[^>]*viewport[^>]*>/i.test(html),
  hasResponsiveCSS: /@media|max-width:\s*\d|min-width:\s*\d|flexbox|grid/i.test(html),
  hasAnalytics: /(google-analytics|gtag|ga\('|analytics\.js|googletagmanager|fbq\()/i.test(html),
  hasSchema: /(schema\.org|application\/ld\+json|itemprop|itemscope|itemtype)/i.test(html),
  hasSitemap: /sitemap\.xml/i.test(html),
  hasChatWidget: /(chat|intercom|drift|zendesk|tawk\.to|livechat|messenger)/i.test(html),
  title: ((html.match(/<title[^>]*>([^<]+)<\/title>/i) || [])[1] || '').trim(),
  metaDescription: ((html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']/i) || [])[1] || '').trim(),
  imageCount: (html.match(/<img[^>]*>/gi) || []).length,
  linkCount: (html.match(/<a[^>]*>/gi) || []).length,
  wordCount: html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().split(' ').length
};

let psScores = { performance: 0, accessibility: 0, bestPractices: 0, seo: 0, fcp: 0, lcp: 0, tbt: 0, cls: 0, speedIndex: 0 };

if (psResp?.json?.lighthouseResult) {
  const lh = psResp.json.lighthouseResult;
  const cats = lh.categories || {};
  const audits = lh.audits || {};

  psScores = {
    performance: Math.round((cats.performance?.score || 0) * 100),
    accessibility: Math.round((cats.accessibility?.score || 0) * 100),
    bestPractices: Math.round((cats['best-practices']?.score || 0) * 100),
    seo: Math.round((cats.seo?.score || 0) * 100),
    fcp: Math.round((audits['first-contentful-paint']?.numericValue || 0) / 1000 * 10) / 10,
    lcp: Math.round((audits['largest-contentful-paint']?.numericValue || 0) / 1000 * 10) / 10,
    tbt: Math.round(audits['total-blocking-time']?.numericValue || 0),
    cls: Math.round((audits['cumulative-layout-shift']?.numericValue || 0) * 100) / 100,
    speedIndex: Math.round((audits['speed-index']?.numericValue || 0) / 1000 * 10) / 10
  };
}

const overallScore = Math.round(
  (analysis.hasHttps ? 15 : 0) +
  (analysis.hasViewport ? 10 : 0) +
  (analysis.hasResponsiveCSS ? 10 : 0) +
  (psScores.performance * 0.25) +
  (psScores.accessibility * 0.10) +
  (psScores.bestPractices * 0.10) +
  (psScores.seo * 0.05) +
  (analysis.hasCTA ? 10 : 0) +
  (analysis.hasForm ? 10 : 0) +
  ((analysis.hasPhoneLink || analysis.hasEmailLink) ? 5 : 0) +
  (analysis.hasAnalytics ? 5 : 0)
);

const issues = [];
if (!analysis.hasHttps) issues.push('No HTTPS encryption');
if (!analysis.hasViewport) issues.push('Not mobile-friendly (no viewport meta)');
if (psScores.performance < 50) issues.push('Slow performance (PageSpeed < 50)');
if (!analysis.hasCTA) issues.push('Missing call-to-action');
if (!analysis.hasForm) issues.push('No contact form found');
if (!analysis.hasAnalytics) issues.push('No analytics tracking');
if (!analysis.hasSchema) issues.push('No schema markup for SEO');

const priorityScore = Math.round((100 - overallScore) * 0.7 + (issues.length * 8));

let redesignReason = '';
if (overallScore < 30) {
  redesignReason = 'Critical: Complete website redesign needed. Missing essential conversion elements.';
} else if (overallScore < 50) {
  redesignReason = 'Major improvements needed: ' + issues.slice(0, 3).join(', ') + '.';
} else if (overallScore < 70) {
  redesignReason = 'Moderate issues: ' + issues.slice(0, 2).join(', ') + '.';
} else {
  redesignReason = 'Minor optimizations available for better conversion.';
}

return {
  leadId: $('Filter Unscored Leads').first().json.leadId,
  businessName: $('Filter Unscored Leads').first().json.businessName,
  website: analysis.url,
  overallScore: overallScore,
  priorityScore: Math.min(priorityScore, 100),
  pageSpeedScores: psScores,
  analysis: analysis,
  issues: issues,
  issueCount: issues.length,
  redesignReason: redesignReason,
  isHighPriority: priorityScore >= 70,
  auditedAt: new Date().toISOString()
};

const audit = $input.first().json;

const updateRow = {
  id: audit.leadId,
  websiteScore: String(audit.overallScore),
  updatedAt: new Date().toISOString()
};

return { leadId: audit.leadId, websiteScore: audit.overallScore, updatedAt: updateRow.updatedAt };

const audit = $input.first().json;

return {
  auditComplete: true,
  leadId: audit.leadId,
  businessName: audit.businessName,
  overallScore: audit.overallScore,
  priorityScore: audit.priorityScore,
  isHighPriority: audit.isHighPriority,
  issuesFound: audit.issueCount,
  nextStep: 'email-extraction',
  timestamp: new Date().toISOString()
};
